window.showToast=function(t,s="success"){const o=document.getElementById("toast-container");if(!o)return;const e=document.createElement("div"),n=s==="success"?"bg-surface2 border-green-500/40 text-green-400":"bg-surface2 border-orange/40 text-orange";e.className=`${n} border px-5 py-3 rounded-xl text-sm font-medium shadow-xl animate-slide-up pointer-events-auto flex items-center gap-2`,e.innerHTML=s==="success"?`<svg class="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="20 6 9 17 4 12"/></svg>${t}`:`<svg class="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>${t}`,o.appendChild(e),setTimeout(()=>{e.style.transition="opacity 0.3s ease, transform 0.3s ease",e.style.opacity="0",e.style.transform="translateY(8px)",setTimeout(()=>e.remove(),300)},2500)};
